     1→import { performance } from 'perf_hooks';
     2→
     3→import { Logger } from '@nestjs/common';
     4→
     5→import { bufferedRollbar, RollbarBuffer } from '@config/rollbar-buffer.config';
     6→
     7→import { EXECUTION_TIME_THRESHOLD_MS } from '@constants/env-variables.constant';
     8→
     9→export interface LogExecutionOptions<TParams, TResponse> {
    10→	logParams?: boolean;
    11→	logResponse?: boolean;
    12→	logExecutionTime?: boolean;
    13→	logErrToRollbar?: boolean;
    14→	logLongExecution?: boolean;
    15→	rollbarLevel?: 'debug' | 'info' | 'warning' | 'error';
    16→	maskSensitiveData?: boolean;
    17→	sensitiveKeys?: string[];
    18→	customContext?: Record<string, unknown>;
    19→	paramFormatter?: (params: TParams) => unknown;
    20→	responseFormatter?: (response: TResponse) => unknown;
    21→}
    22→
    23→const DEFAULT_OPTIONS: LogExecutionOptions<unknown, unknown> = {
    24→	logParams: true,
    25→	logResponse: true,
    26→	logExecutionTime: true,
    27→	logErrToRollbar: true,
    28→	logLongExecution: true,
    29→	rollbarLevel: 'debug',
    30→	maskSensitiveData: true,
    31→	sensitiveKeys: [
    32→		'password',
    33→		'pass',
    34→		'token',
    35→		'secret',
    36→		'auth',
    37→		'authorization',
    38→		'cookie',
    39→		'session',
    40→		'credentials',
    41→		'apiKey',
    42→		'_cookie',
    43→		'csrf',
    44→		'_csrf',
    45→	],
    46→	paramFormatter: <TParams>(params: TParams) => params,
    47→	responseFormatter: <TResponse>(response: TResponse) => response,
    48→};
    49→
    50→const thresholdMs = Number(process.env[EXECUTION_TIME_THRESHOLD_MS]);
    51→
    52→export function LogExecution<TParams, TResponse>(
    53→	options: LogExecutionOptions<TParams, TResponse> = {},
    54→): MethodDecorator {
    55→	const config: LogExecutionOptions<TParams, TResponse> = {
    56→		...DEFAULT_OPTIONS,
    57→		...options,
    58→	};
    59→
    60→	return function (
    61→		target: unknown,
    62→		propertyKey: string | symbol,
    63→		descriptor: PropertyDescriptor,
    64→	) {
    65→		const originalMethod = descriptor.value as (...args: unknown[]) => unknown;
    66→		const className = (target as { constructor: { name: string } }).constructor.name;
    67→		const methodName = String(propertyKey);
    68→		const logger = new Logger(`${className}.${methodName}`);
    69→
    70→		descriptor.value = async function (...args: unknown[]) {
    71→			const startTime = performance.now();
    72→
    73→			try {
    74→				const logContext = {
    75→					className,
    76→					methodName,
    77→					timestamp: new Date().toISOString(),
    78→					...(config.customContext ?? {}),
    79→				};
    80→
    81→				let paramsToLog: unknown = config.paramFormatter
    82→					? config.paramFormatter(args as TParams)
    83→					: args;
    84→				if (config.maskSensitiveData) {
    85→					paramsToLog = maskSensitiveData(paramsToLog, config.sensitiveKeys);
    86→				}
    87→
    88→				if (config.logParams) {
    89→					logger.log(
    90→						`[LogExecution]: Method invoked with parameters, ${JSON.stringify({
    91→							params: paramsToLog,
    92→							...logContext,
    93→						})}`,
    94→					);
    95→				}
    96→
    97→				const result = await originalMethod.apply(this, args);
    98→				const endTime = performance.now();
    99→				const executionTime = endTime - startTime;
   100→
   101→				let responseToLog: unknown = config.responseFormatter
   102→					? config.responseFormatter(result as TResponse)
   103→					: result;
   104→				if (config.maskSensitiveData) {
   105→					responseToLog = maskSensitiveData(responseToLog, config.sensitiveKeys);
   106→				}
   107→
   108→				const successLogContext = {
   109→					...logContext,
   110→					executionTimeMs: executionTime,
   111→					response: config.logResponse ? responseToLog : undefined,
   112→				};
   113→
   114→				if (config.logExecutionTime) {
   115→					logger.log(
   116→						`[LogExecution]:Method completed in ${executionTime.toFixed(2)}ms. Result: ${JSON.stringify(successLogContext)}`,
   117→					);
   118→				}
   119→
   120→				if (executionTime > thresholdMs) {
   121→					logger.warn(
   122→						`[LogExecution]: Long execution ${executionTime.toFixed(
   123→							2,
   124→						)}ms, logContext: ${JSON.stringify({ ...successLogContext, success: true })}`,
   125→					);
   126→
   127→					if (config.logLongExecution) {
   128→						try {
   129→							const instance = getRollbarBufferInstance();
   130→							if (instance) {
   131→								instance.warning(
   132→									`[LogExecution]: Long execution ${executionTime.toFixed(2)}ms.`,
   133→									{ ...successLogContext, success: true },
   134→								);
   135→							}
   136→						} catch {}
   137→					}
   138→				}
   139→
   140→				return result;
   141→			} catch (error) {
   142→				const endTime = performance.now();
   143→				const executionTime = endTime - startTime;
   144→				const errorLogContext = {
   145→					className,
   146→					methodName,
   147→					timestamp: new Date().toISOString(),
   148→					executionTimeMs: executionTime,
   149→					error: {
   150→						message: (error as Error).message,
   151→						stack: (error as Error).stack,
   152→						name: (error as Error).name,
   153→					},
   154→					...(config.customContext ?? {}),
   155→				};
   156→
   157→				logger.error(
   158→					`[LogExecution]: Method failed after ${executionTime.toFixed(2)}ms: ${
   159→						(error as Error).message
   160→					}, errorLogContext: ${JSON.stringify(errorLogContext)}`,
   161→				);
   162→
   163→				if (config.logErrToRollbar) {
   164→					try {
   165→						const instance = getRollbarBufferInstance();
   166→						if (instance) {
   167→							instance.error(`Method ${className}.${methodName} failed.`, {
   168→								...errorLogContext,
   169→								errorMessage: (error as Error).message,
   170→								errorStack: (error as Error).stack,
   171→								success: false,
   172→							});
   173→						}
   174→					} catch {}
   175→				}
   176→
   177→				throw error;
   178→			}
   179→		};
   180→
   181→		return descriptor;
   182→	};
   183→}
   184→
   185→function maskSensitiveData(data: unknown, sensitiveKeys: string[] = []): unknown {
   186→	if (!data || typeof data !== 'object') {
   187→		return data;
   188→	}
   189→
   190→	if (Array.isArray(data)) {
   191→		return data.map((item) => maskSensitiveData(item, sensitiveKeys));
   192→	}
   193→
   194→	const masked = { ...data } as Record<string, unknown>;
   195→
   196→	for (const key in masked) {
   197→		if (Object.prototype.hasOwnProperty.call(masked, key)) {
   198→			const lowerKey = key.toLowerCase();
   199→
   200→			if (
   201→				sensitiveKeys.some((sensitiveKey) =>
   202→					lowerKey.includes(sensitiveKey.toLowerCase()),
   203→				)
   204→			) {
   205→				masked[key] = '***MASKED***';
   206→			} else if (typeof masked[key] === 'object' && masked[key] !== null) {
   207→				masked[key] = maskSensitiveData(masked[key], sensitiveKeys);
   208→			}
   209→		}
   210→	}
   211→
   212→	return masked;
   213→}
   214→
   215→function getRollbarBufferInstance(): RollbarBuffer | null {
   216→	return bufferedRollbar;
   217→}
